INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('afa792ec-5971-53a8-a4ca-10f21e3027d3', '71b0fee4-b5db-52e4-8e51-14426ab378c6', 'سقط شعاع ضوئي على مرآة مستوية بزاوية ورود تساوي 40°. ما زاوية الانعكاس؟', '[{"id":"a","text":"80°"},{"id":"b","text":"50°"},{"id":"c","text":"90°"},{"id":"d","text":"40°"}]'::jsonb, 'd', 'وفق القانون الثاني للانعكاس: زاوية الانعكاس = زاوية الورود، إذن r = i = 40°.', 3)
