INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('df25cbc2-c7e3-5ff2-9847-7b1d36b7ee43', 'a18d4cb2-cdcc-506c-86e8-d099fa6d96e1', 'سقط شعاع ضوئي على مرآة مستوية فكانت زاوية انعكاسه 55°. ما زاوية وروده؟', '[{"id":"a","text":"110°"},{"id":"b","text":"35°"},{"id":"c","text":"90°"},{"id":"d","text":"55°"}]'::jsonb, 'd', 'بتطبيق قانون الانعكاس i = r، إذا كانت زاوية الانعكاس 55° فزاوية الورود = 55° أيضًا.', 2)
