  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3be8161b-761a-5a62-a43a-fb96a0c3efb5', 'cfe8e5ad-8d29-5084-9e65-d6fb15aae2aa', 'في العين البشرية، أين تتكوّن صورة الأجسام التي ننظر إليها؟', '[{"id":"a","text":"على الشبكية (حقيقية مقلوبة)"},{"id":"b","text":"على قرنية العين"},{"id":"c","text":"أمام عدسة العين (تخيّلية)"},{"id":"d","text":"داخل العدسيّة نفسها"}]'::jsonb, 'a', 'عدسة العين (العدسيّة) تجمّع الأشعة وتكوّن صورة حقيقية مقلوبة على الشبكية. ثمّ يُعالج الدماغ هذه الصورة ويجعلها معتدلة في الإدراك.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a171368a-bd36-5525-b952-4b9ba55fefdc', 'cfe8e5ad-8d29-5084-9e65-d6fb15aae2aa', 'عدسة مجمّعة بُعدها البؤري 10 سم. جسم على بُعد 20 سم منها. ما طبيعة الصورة؟', '[{"id":"a","text":"حقيقية مقلوبة مساوية للجسم"},{"id":"b","text":"تخيّلية مكبّرة معتدلة"},{"id":"c","text":"حقيقية مقلوبة مصغّرة"},{"id":"d","text":"لا تتكوّن صورة"}]'::jsonb, 'a', 'البُعد البؤري f = 10 سم، والجسم على بُعد d = 20 سم = 2f. عند d = 2f تكون الصورة حقيقية مقلوبة ومساوية للجسم في الحجم، وتقع على البُعد 2f من الجهة الأخرى.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
