INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dc852d16-39cc-580a-94c7-c31d1e146368', '24df4d84-60f7-5d08-804d-2b85bc32228b', 'محلول له pH = 3، ما طبيعته؟', '[{"id":"a","text":"قاعدي"},{"id":"b","text":"متعادل"},{"id":"c","text":"حمضي"},{"id":"d","text":"لا يمكن التحديد"}]'::jsonb, 'c', 'pH = 3 أقلّ من 7، إذن المحلول حمضي. كلّما ابتعد pH عن 7 نحو 0 كلّما زادت حمضية المحلول.', 1)
