INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6a308347-9fb2-5918-a818-9da7e2510b26', 'e5ca2d8d-4123-5574-90f6-a5c907c89481', 'أضفنا كاشف عبّاد الشمس إلى محلول مجهول فأصبح لون المحلول أحمر. ما طبيعة المحلول؟', '[{"id":"a","text":"حمضي"},{"id":"b","text":"متعادل"},{"id":"c","text":"قاعدي"},{"id":"d","text":"لا يمكن التحديد من هذا الكاشف"}]'::jsonb, 'a', 'عبّاد الشمس يتحوّل إلى اللون الأحمر في الوسط الحمضي (pH < 7)، وإلى الأرجواني في الوسط المتعادل، وإلى الأزرق في الوسط القاعدي.', 2)
