INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('03d3ffec-8982-54e8-af46-bdc34a74db49', '9795d4ab-4ba5-58f5-bbb7-a2d8a35ab255', 'أيّ ممّا يلي يُعرَّف بأنّه أيون موجب (كاتيون)؟', '[{"id":"a","text":"Cl⁻"},{"id":"b","text":"Na⁺"},{"id":"c","text":"OH⁻"},{"id":"d","text":"SO₄²⁻"}]'::jsonb, 'b', 'Na⁺ هو أيون الصوديوم ويحمل شحنة موجبة (+1)، لذا هو كاتيون. أمّا Cl⁻ و OH⁻ و SO₄²⁻ فكلّها أنيونات (شحنات سالبة).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ba4c35da-a412-5a63-b560-0ae9098103da', '9795d4ab-4ba5-58f5-bbb7-a2d8a35ab255', 'غمسنا قطبَين في محلول سكّر وأغلقنا الدائرة الكهربائية. ماذا نلاحظ؟', '[{"id":"a","text":"تضيء اللمبة بشدّة"},{"id":"b","text":"لا تضيء اللمبة"},{"id":"c","text":"تضيء اللمبة ببريق خافت"},{"id":"d","text":"تنطفئ اللمبة تدريجيًّا"}]'::jsonb, 'b', 'محلول السكّر غير شاردي: السكّر يذوب في الماء دون أن ينتج شوارد، لذا لا يوجد ناقل للتيار الكهربائي واللمبة لا تضيء.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f135d69e-e440-5280-a33f-857bd03ac27c', '9795d4ab-4ba5-58f5-bbb7-a2d8a35ab255', 'الجسيم الذي يحمل شحنة كهربائية سالبة في المحلول يُسمّى:', '[{"id":"a","text":"كاتيون"},{"id":"b","text":"بروتون"},{"id":"c","text":"أنيون"},{"id":"d","text":"نيوترون"}]'::jsonb, 'c', 'الأنيون هو الأيون السالب (يحمل شحنة سالبة)، مثل Cl⁻ و OH⁻ و SO₄²⁻. أمّا الكاتيون فهو الأيون الموجب.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('50b9583a-ed55-5045-8898-733dee8955c0', '9795d4ab-4ba5-58f5-bbb7-a2d8a35ab255', 'ما الشوارد الناتجة عن إذابة NaCl في الماء؟', '[{"id":"a","text":"Na²⁺ و Cl²⁻"},{"id":"b","text":"Na⁻ و Cl⁺"},{"id":"c","text":"Na⁺ و Cl⁻"},{"id":"d","text":"NaCl يبقى بلا تشرّد"}]'::jsonb, 'c', 'عند إذابة كلوريد الصوديوم NaCl في الماء يتشرّد إلى Na⁺ (كاتيون بشحنة +1) و Cl⁻ (أنيون بشحنة −1).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0a82487d-cc54-5bcb-822d-c146d76f1434', '9795d4ab-4ba5-58f5-bbb7-a2d8a35ab255', 'أيّ المحاليل التالية ينقل التيار الكهربائي؟', '[{"id":"a","text":"محلول السكّر في الماء"},{"id":"b","text":"ماء البحر"},{"id":"c","text":"الكحول الخالص"},{"id":"d","text":"الزيت"}]'::jsonb, 'b', 'ماء البحر غنيّ بشوارد Na⁺ و Cl⁻ وغيرها، فهو ناقل قويّ للتيار الكهربائي. أمّا محلول السكّر والكحول والزيت فهي غير شاردية لا تنقل التيار.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9db33979-7743-5936-b6c7-a3d6f94ceca9', '9795d4ab-4ba5-58f5-bbb7-a2d8a35ab255', 'إذا خفّفنا محلول NaCl المركّز بإضافة الماء، ماذا يحدث للناقلية الكهربائية؟', '[{"id":"a","text":"تزيد الناقلية"},{"id":"b","text":"تنقص الناقلية"},{"id":"c","text":"تنعدم الناقلية تمامًا"},{"id":"d","text":"لا تتغيّر الناقلية"}]'::jsonb, 'b', 'التخفيف يُقلّل تركيز الشوارد في وحدة الحجم، فتنقص الناقلية الكهربائية للمحلول. لكنّ المحلول يبقى شارديًّا (لا تنعدم الناقلية تمامًا).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

